import Card from "../Card/Card";
import React from "react";

function Cards({ characters }) {
  const onClose = () => {
    window.alert("Emulamos que se cierra la card");
  };

  return (
    <div>
      {characters.map((character) => {
        return (
          <Card
            key={character.id}
            character = {character}
            onClose={onClose}
          />
        );
      })}
    </div>
  );
}

export default Cards;
